query:
UPDATE reviews r SET r.contentTitle = COALESCE(
  (SELECT vh.title FROM viewing_history vh WHERE vh.tmdbId = r.tmdbId AND vh.mediaType = r.mediaType LIMIT 1),
  (SELECT w.title FROM watchlist w WHERE w.tmdbId = r.tmdbId AND w.mediaType = r.mediaType LIMIT 1),
  (SELECT a.title FROM alerts a WHERE a.tmdbId = r.tmdbId AND a.mediaType = r.mediaType LIMIT 1),
  (SELECT cli.title FROM custom_list_items cli WHERE cli.tmdbId = r.tmdbId AND cli.mediaType = r.mediaType LIMIT 1)
) WHERE r.contentTitle IS NULL;

